use crate::decoders::{Crack, CrackResult, Decoder, check_string_success};use crate::checkers::CheckerTypes;use std::marker::PhantomData;pub struct AtbashDecoder;fn atbash_char(c: char) -> Option<char> {    if c.is_ascii_uppercase() {        Some((b'Z' - (c as u8 - b'A')) as char)    } else if c.is_ascii_lowercase() {        Some((b'z' - (c as u8 - b'a')) as char)    } else {        Some(c)    }}impl Crack for Decoder<AtbashDecoder> {    fn crack(&self, text: &str, checker: &CheckerTypes) -> CrackResult {        let mut result = CrackResult::new(self.get_name(), self.get_description(), self.get_link());        result.encrypted_text = text.to_string();        let decoded: String = text.chars().filter_map(atbash_char).collect();        if check_string_success(&decoded, text) {            let check_result = checker.check_text(&decoded);            if check_result.is_identified {                result.success = true;                result.unencrypted_text = Some(vec![decoded]);                result.checker_name = check_result.checker_name;            }        }        result    }    fn get_name(&self) -> &'static str { "Atbash" }    fn get_popularity(&self) -> f32 { 0.5 }    fn get_tags(&self) -> &'static [&'static str] { &["atbash", "decoder", "cipher"] }    fn get_description(&self) -> &'static str { "Atbash is a substitution cipher that maps A->Z, B->Y, C->X, and so on." }    fn get_link(&self) -> &'static str { "https://en.wikipedia.org/wiki/Atbash" }}impl Decoder<AtbashDecoder> {    pub fn new() -> Self {        Decoder {            name: "Atbash",            description: "Atbash is a substitution cipher that maps A->Z, B->Y, C->X, and so on.",            link: "https://en.wikipedia.org/wiki/Atbash",            tags: vec!["atbash", "decoder", "cipher"],            popularity: 0.5,            phantom: PhantomData,        }    }}



